import type { JSONSupport } from "../../core/JSONSupport.js";

export interface TopFilterProperties extends Partial<Pick<TopFilter, "groupByFields" | "orderByFields" | "topCount">> {}

/**
 * This class defines the top filter parameters for executing top features queries for features from a [FeatureLayer](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/).
 * This parameter must be set on the [TopFeaturesQuery.topFilter](https://developers.arcgis.com/javascript/latest/references/core/rest/support/TopFeaturesQuery/#topFilter) object when calling any of top query methods on
 * a FeatureLayer. It is used to set the [groupByFields](https://developers.arcgis.com/javascript/latest/references/core/rest/support/TopFilter/#groupByFields), [orderByFields](https://developers.arcgis.com/javascript/latest/references/core/rest/support/TopFilter/#orderByFields), and [count](https://developers.arcgis.com/javascript/latest/references/core/rest/support/TopFilter/#topCount) criteria used the top features query.
 * For example, you can use FeatureLayer's [FeatureLayer.queryTopFeatures()](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#queryTopFeatures) method to query the most populous three counties
 * in each state of the United States.
 *
 * ```js
 * // query the top three most populous counties from each state.
 * // Results will be ordered based the population of each county in descending order
 * // top query will run against all features available in the service
 * const query = new TopFeaturesQuery({
 *   outFields: ["State, Pop_total, County"],
 *   topFilter: new TopFilter({
 *     topCount: 3,
 *     groupByFields: ["State"],
 *     orderByFields: ["Pop_total DESC"]
 *   })
 * });
 * featureLayer.queryTopFeatures(query)
 *   .then(function(response){
 *      // returns a feature set with features containing the most populous
 *      // three counties in each state ordered by the number of population.
 *      // The following attributes are returned as well: State, Pop_total, County
 *    });
 * ```
 *
 * @since 4.20
 * @see [TopFeaturesQuery](https://developers.arcgis.com/javascript/latest/references/core/rest/support/TopFeaturesQuery/)
 * @see [FeatureLayer.queryTopFeatures()](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#queryFeatures)
 * @see [Query and filter guide](https://developers.arcgis.com/javascript/latest/query-filter/)
 * @see [Sample - Aggregate spatial statistics](https://developers.arcgis.com/javascript/latest/sample-code/featurelayer-query-aggregate/)
 */
export default class TopFilter extends JSONSupport {
  constructor(properties?: TopFilterProperties);
  /**
   * When one or more field names are provided in this property, the output
   * result will be grouped based on unique values from those fields.
   */
  accessor groupByFields: string[] | null | undefined;
  /**
   * One or more field names used to order the query results. Specify `ASC` (ascending) or `DESC`
   * (descending) after the field name to control the order. The default order is `ASC`.
   *
   * @example
   * const query = new TopFeaturesQuery({
   *   outFields: ["State, Pop_total, County"],
   *   topFilter: new TopFilter({
   *     topCount: 3,
   *     groupByFields: ["State"],
   *     orderByFields: ["Pop_total DESC"]
   *   })
   * });
   */
  accessor orderByFields: string[] | null | undefined;
  /**
   * Defines the number of features to be returned from the top features query.
   *
   * @example
   * const query = new TopFeaturesQuery({
   *   outFields: ["State, Pop_total, County"],
   *   topFilter: new TopFilter({
   *     topCount: 3,
   *     groupByFields: ["State"],
   *     orderByFields: ["Pop_total DESC"]
   *   })
   * });
   */
  accessor topCount: number | null | undefined;
  /**
   * Creates a deep clone of TopFilter object.
   *
   * @returns A new instance of a TopFilter object equal to the object used to call `.clone()`.
   */
  clone(): TopFilter;
}